phase1.code:
#include <iostream>
#include <string>

int main() {
    std::cout << "=== String Manipulation ===" << std::endl;

    // Creating strings
    std::string playerName = "Hero";
    std::string greeting = "Welcome, ";

    // Concatenation
    std::string message = greeting + playerName + "!";
    std::cout << message << std::endl;

    // String length
    std::string gameTitle = "Dungeon Quest";
    std::cout << "Title: '" << gameTitle << "' (" << gameTitle.length() << " characters)" << std::endl;

    // Accessing characters
    std::cout << "First character: " << gameTitle[0] << std::endl;
    std::cout << "Last character: " << gameTitle[gameTitle.length() - 1] << std::endl;

    // Substring
    std::string sub = gameTitle.substr(0, 7);  // "Dungeon"
    std::cout << "Substring (0-7): '" << sub << "'" << std::endl;

    // Find
    std::string sentence = "The hero defeated the dragon.";
    size_t pos = sentence.find("dragon");
    if (pos != std::string::npos) {
        std::cout << "Found 'dragon' at position " << pos << std::endl;
    }

    // Replace
    std::string story = "The player opened the chest.";
    story.replace(story.find("player"), 6, "hero");
    std::cout << "Replaced: " << story << std::endl;

    // Uppercase/Lowercase (manual)
    std::string power = "FIREBALL";
    for (char& c : power) {
        c = std::tolower(c);
    }
    std::cout << "Lowercase: " << power << std::endl;

    // Checking if empty
    std::string empty = "";
    if (empty.empty()) {
        std::cout << "String is empty!" << std::endl;
    }

    // Comparison
    std::string str1 = "Apple";
    std::string str2 = "Banana";
    if (str1 < str2) {
        std::cout << str1 << " comes before " << str2 << std::endl;
    }

    return 0;
}

