phase3.solution:
#include <iostream>
#include <string>

int main() {
    std::string playerName = "Hero";
    std::string item = "Sword";

    std::string message = playerName + " found a " + item + "!";
    std::cout << "Message: " << message << std::endl;

    std::cout << "Length: " << message.length() << std::endl;

    size_t pos = message.find("Sword");
    std::cout << "'Sword' found at position: " << pos << std::endl;

    message.replace(pos, 5, "Shield");
    std::cout << "Updated message: " << message << std::endl;

    return 0;
}
